import argparse
import json
import os
from pathlib import Path

import numpy as np
import soundfile as sf
import torch
import torchaudio
from torch.utils.data import DataLoader, Dataset, Sampler
from transformers import AutoFeatureExtractor

from model import build_model


def find_test_root(data_path: str) -> Path:
    seeds = [data_path, os.environ.get('RAB_DATA_DIR'), '/data', '/rab_data', '/workspace', '.']
    seen = set()
    candidates = []
    for p in seeds:
        if not p:
            continue
        root = Path(p)
        try:
            root = root.resolve()
        except Exception:
            pass
        if not root.exists() or str(root) in seen:
            continue
        seen.add(str(root))
        candidates.append(root)
        if root.is_dir():
            try:
                for child in root.rglob('*'):
                    if child.is_dir():
                        candidates.append(child)
            except Exception:
                pass
    uniq = []
    seen = set()
    for p in candidates:
        try:
            p = p.resolve()
        except Exception:
            pass
        if str(p) not in seen:
            seen.add(str(p))
            uniq.append(p)
    for cand in uniq:
        if (cand / 'test.txt').is_file() and (cand / 'flac').is_dir():
            return cand
    raise FileNotFoundError(f'Could not locate test root under {data_path}')


def load_audio(path: Path) -> np.ndarray:
    try:
        wav, sr = sf.read(str(path), always_2d=False)
        if wav.ndim > 1:
            wav = wav.mean(axis=1)
        wav = wav.astype(np.float32)
        if sr != 16000:
            raise ValueError(f'Expected 16000 Hz, got {sr}')
        return wav
    except Exception:
        wav, sr = torchaudio.load(str(path))
        if wav.dim() == 2 and wav.size(0) > 1:
            wav = wav.mean(dim=0, keepdim=True)
        wav = wav.squeeze(0).float().cpu().numpy().astype(np.float32)
        if sr != 16000:
            raise ValueError(f'Expected 16000 Hz, got {sr}')
        return wav


def get_num_frames(path: Path) -> int:
    try:
        return int(sf.info(str(path)).frames)
    except Exception:
        wav, _ = torchaudio.load(str(path))
        return int(wav.shape[-1])


class TestDataset(Dataset):
    def __init__(self, data_path: str):
        self.root = find_test_root(data_path)
        self.flac_dir = self.root / 'flac'
        with open(self.root / 'test.txt') as f:
            self.utt_ids = [line.strip() for line in f if line.strip()]
        self.paths = [self.flac_dir / f'{u}.flac' for u in self.utt_ids]
        self.lengths = [get_num_frames(p) for p in self.paths]

    def __len__(self):
        return len(self.utt_ids)

    def __getitem__(self, idx):
        return {'input_values': load_audio(self.paths[idx]), 'index': idx}


class SortedBatchSampler(Sampler):
    def __init__(self, lengths, batch_size: int):
        self.batch_size = batch_size
        self.indices = np.argsort(np.asarray(lengths)).tolist()

    def __iter__(self):
        batch = []
        for idx in self.indices:
            batch.append(idx)
            if len(batch) == self.batch_size:
                yield batch
                batch = []
        if batch:
            yield batch

    def __len__(self):
        return (len(self.indices) + self.batch_size - 1) // self.batch_size


class Collator:
    def __init__(self, feature_extractor):
        self.feature_extractor = feature_extractor

    def __call__(self, batch):
        wavs = [b['input_values'] for b in batch]
        enc = self.feature_extractor(
            wavs,
            sampling_rate=16000,
            return_tensors='pt',
            padding=True,
            return_attention_mask=True,
        )
        input_values = enc['input_values']
        attention_mask = enc['attention_mask'] if 'attention_mask' in enc else torch.ones_like(input_values, dtype=torch.long)
        indices = torch.tensor([b['index'] for b in batch], dtype=torch.long)
        return {'input_values': input_values, 'attention_mask': attention_mask, 'index': indices}


def extract_state_dict(ckpt: dict):
    if not isinstance(ckpt, dict):
        return ckpt
    for key in ['model_state_dict', 'state_dict', 'model_state']:
        if key in ckpt and isinstance(ckpt[key], dict):
            return ckpt[key]
    tensor_like = [v for v in ckpt.values() if torch.is_tensor(v)]
    if tensor_like:
        return ckpt
    raise ValueError('Could not extract model state dict from checkpoint')


def infer_model_config(ckpt: dict, state: dict):
    if isinstance(ckpt, dict):
        if 'model_config' in ckpt and isinstance(ckpt['model_config'], dict):
            return ckpt['model_config']
        if 'model_kwargs' in ckpt and isinstance(ckpt['model_kwargs'], dict):
            cfg = dict(ckpt['model_kwargs'])
            if 'encoder_name' not in cfg and 'encoder_name' in ckpt:
                cfg['encoder_name'] = ckpt['encoder_name']
            return cfg
    encoder_name = None
    if isinstance(ckpt, dict):
        encoder_name = ckpt.get('encoder_name')
    if encoder_name is None:
        lw = state.get('layer_weights')
        if lw is not None and hasattr(lw, 'numel'):
            n = int(lw.numel())
            if n == 13:
                encoder_name = 'facebook/wav2vec2-base'
            elif n == 25:
                encoder_name = 'facebook/wav2vec2-xls-r-300m'
            elif n == 49:
                encoder_name = 'microsoft/wavlm-large'
    if encoder_name is None:
        encoder_name = 'facebook/wav2vec2-xls-r-300m'
    proj_dim = 256
    if 'head.0.weight' in state:
        proj_dim = int(state['head.0.weight'].shape[0])
    use_layer_weights = 'layer_weights' in state
    return {
        'encoder_name': encoder_name,
        'pooling': 'attentive',
        'proj_dim': proj_dim,
        'dropout': 0.2,
        'unfreeze_last_n_layers': 0,
        'use_layer_weights': use_layer_weights,
    }


def load_feature_extractor(ckpt: dict, model_cfg: dict):
    local_dir = None
    if isinstance(ckpt, dict):
        local_dir = ckpt.get('feature_extractor_local_dir')
    candidates = []
    if local_dir:
        candidates.append(local_dir)
    candidates.append('artifacts/feature_extractor')
    candidates.append(model_cfg['encoder_name'])
    for cand in candidates:
        try:
            return AutoFeatureExtractor.from_pretrained(cand, local_files_only=True)
        except Exception:
            try:
                return AutoFeatureExtractor.from_pretrained(cand)
            except Exception:
                pass
    raise RuntimeError('Failed to load feature extractor')


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True)
    parser.add_argument('--checkpoint', required=True)
    parser.add_argument('--output', required=True)
    parser.add_argument('--batch_size', type=int, default=64)
    args = parser.parse_args()

    device = 'cuda' if torch.cuda.is_available() else 'cpu'
    ckpt = torch.load(args.checkpoint, map_location='cpu')
    state = extract_state_dict(ckpt)
    model_cfg = infer_model_config(ckpt, state)
    feature_extractor = load_feature_extractor(ckpt, model_cfg)

    model = build_model(model_cfg)
    missing, unexpected = model.load_state_dict(state, strict=False)
    if unexpected:
        raise RuntimeError(f'Unexpected keys in state_dict: {unexpected[:20]}')
    if missing:
        raise RuntimeError(f'Missing keys in state_dict: {missing[:20]}')
    model.to(device)
    model.eval()

    dataset = TestDataset(args.data_path)
    loader = DataLoader(
        dataset,
        batch_sampler=SortedBatchSampler(dataset.lengths, args.batch_size),
        num_workers=0,
        collate_fn=Collator(feature_extractor),
        pin_memory=torch.cuda.is_available(),
    )

    scores = np.zeros(len(dataset), dtype=np.float32)
    amp_enabled = torch.cuda.is_available()
    with torch.no_grad():
        for batch in loader:
            input_values = batch['input_values'].to(device, non_blocking=True)
            attention_mask = batch['attention_mask'].to(device, non_blocking=True)
            with torch.amp.autocast('cuda', dtype=torch.bfloat16, enabled=amp_enabled):
                logits = model(input_values=input_values, attention_mask=attention_mask)
            scores[batch['index'].numpy()] = logits.float().cpu().numpy()

    out_path = Path(args.output)
    out_path.parent.mkdir(parents=True, exist_ok=True)
    with out_path.open('w') as f:
        json.dump({'predictions': [float(x) for x in scores.tolist()]}, f)


if __name__ == '__main__':
    main()
